#ifndef CONTROLLER_H
#define CONTROLLER_H

#include <stdbool.h>
#include <stdint.h>

#define CONTROLLER_TEMP_LOW_THRESHOLD 47
#define CONTROLLER_TEMP_HIGH_THRESHOLD 52
#define CONTROLLER_TEMP_EARLY_OFF_THRESHOLD 50
#define CONTROLLER_SENSOR_TIMEOUT_MS 1000U

typedef enum {
    CONTROLLER_INPUT_NONE = 0,
    CONTROLLER_INPUT_TEMPERATURE,
    CONTROLLER_INPUT_SENSOR_TIMEOUT,
    CONTROLLER_INPUT_INVALID_TEMPERATURE,
} controller_input_kind_t;

typedef enum {
    CONTROLLER_STATE_SAFE_OFF = 0,
    CONTROLLER_STATE_HEATING,
    CONTROLLER_STATE_HOLDING,
} controller_state_t;

typedef struct {
    controller_input_kind_t kind;
    int temperature_c;
    uint32_t now_ms;
} controller_input_t;

typedef struct {
    bool heater_on;
    controller_state_t state;
    bool has_valid_sensor;
    int last_temperature_c;
    uint32_t last_valid_sensor_ms;
} controller_t;

typedef struct {
    bool heater_on;
    controller_state_t state;
    const char *state_name;
    bool changed;
    bool timed_out;
} controller_output_t;

void controller_init(controller_t *controller);
controller_output_t controller_step(controller_t *controller, controller_input_t input);
const char *controller_state_name(controller_state_t state);

#endif

#include "controller.h"

static void controller_set_safe_off(controller_t *controller)
{
    controller->heater_on = false;
    controller->state = CONTROLLER_STATE_SAFE_OFF;
}

void controller_init(controller_t *controller)
{
    if (controller == 0) {
        return;
    }

    controller_set_safe_off(controller);
    controller->has_valid_sensor = false;
    controller->last_temperature_c = 0;
    controller->last_valid_sensor_ms = 0U;
}

controller_output_t controller_step(controller_t *controller, controller_input_t input)
{
    controller_output_t output = {
        .heater_on = false,
        .state = CONTROLLER_STATE_SAFE_OFF,
        .state_name = controller_state_name(CONTROLLER_STATE_SAFE_OFF),
        .changed = false,
        .timed_out = false,
    };
    bool previous_heater_on;
    controller_state_t previous_state;

    if (controller == 0) {
        return output;
    }

    // Boot: Heater should be off on boot
    previous_heater_on = controller->heater_on;
    previous_state = controller->state;

    bool temperature_rising = false;

    switch (input.kind) {
    case CONTROLLER_INPUT_TEMPERATURE:
        controller->has_valid_sensor = true;
        controller->last_temperature_c = input.temperature_c;
        controller->last_valid_sensor_ms = input.now_ms;

        // Check for rising temperature in upper band
        if (input.temperature_c >= CONTROLLER_TEMP_EARLY_OFF_THRESHOLD &&
            input.temperature_c <= CONTROLLER_TEMP_HIGH_THRESHOLD) {
            if (input.temperature_c > previous_temperature_rising_threshold) {
                temperature_rising = true;
            }
        }

        // Apply control policy based on state and temperature
        switch (controller->state) {
        case CONTROLLER_STATE_SAFE_OFF:
            // If temp < 47, turn heater on
            if (input.temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
                controller_set_safe_off(controller);
            }
            break;

        case CONTROLLER_STATE_HEATING:
            // In heating state, don't change unless we're in upper band and not rising
            if (input.temperature_c >= CONTROLLER_TEMP_HIGH_THRESHOLD) {
                // Upper band reached - turn off heater early
                controller->heater_on = false;
                output.state_name = "STATE SAFE_OFF";
                output.timed_out = true;
                return output;
            }

            // If not rising in upper band, preserve safe state
            if (input.temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
                controller->heater_on = false;
                output.state_name = "STATE SAFE_OFF";
                output.timed_out = true;
                return output;
            }

            // In upper band and not rising, preserve safe state
            if (input.temperature_c < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
                controller->heater_on = false;
                output.state_name = "STATE SAFE_OFF";
                output.timed_out = true;
                return output;
            }

            // Not rising in upper band, preserve safe state
            if (input.temperature_c < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
                controller->heater_on = false;
                output.state_name = "STATE SAFE_OFF";
                output.timed_out = true;
                return output;
            }

            // Rising in upper band: turn off early and count as HOLDING
            controller->heater_on = false;
            output.state_name = "STATE HOLDING";
            output.timed_out = true;
            break;

        case CONTROLLER_STATE_HOLDING:
            // In holding state, preserve safe state
            if (input.temperature_c < CONTROLLER_TEMP_LOW_THRESHOLD) {
                controller->heater_on = false;
                output.state_name = "STATE SAFE_OFF";
                output.timed_out = true;
                return output;
            }

            // If not rising in upper band, preserve safe state
            if (input.temperature_c < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
                controller->heater_on = false;
                output.state_name = "STATE SAFE_OFF";
                output.timed_out = true;
                return output;
            }

            // Rising in upper band: turn off early and count as HOLDING
            if (input.temperature_c > previous_temperature_rising_threshold) {
                controller->heater_on = false;
                output.state_name = "STATE HOLDING";
                output.timed_out = true;
                return output;
            }

            // Not rising in upper band, preserve safe state
            if (input.temperature_c < CONTROLLER_TEMP_EARLY_OFF_THRESHOLD) {
                controller->heater_on = false;
                output.state_name = "STATE SAFE_OFF";
                output.timed_out = true;
                return output;
            }

            // Rising in upper band: turn off early and count as HOLDING
            if (input.temperature_c > previous_temperature_rising_threshold) {
                controller->heater_on = false;
                output.state_name = "STATE HOLDING";
                output.timed_out = true;
                return output;
            }

            // Rising in upper band: turn off early and count as HOLDING
            if (input.temperature_c > previous_temperature_rising_threshold) {
